mapper.select:
SELECT COUNT(*)
FROM posts
WHERE category = #{category}
  AND status = #{status}
  AND is_deleted = false

SELECT post_id, user_id, title, content, category,
       view_count, status, like_count, comment_count,
       is_deleted, deleted_at, is_blinded,
       created_at, updated_at, created_by, updated_by
FROM posts
WHERE user_id = #{userId}
  AND status = #{status}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE posts
SET view_count = view_count + 1
WHERE post_id = #{postId}

UPDATE posts
SET like_count = GREATEST(like_count + #{delta}, 0)
WHERE post_id = #{postId}

UPDATE posts
SET comment_count = GREATEST(comment_count + #{delta}, 0)
WHERE post_id = #{postId}

